export default function NutritionPanel() {
const { todayNutrition, dailyGoals } = useApp();

return ( <div> <h3>Calories</h3> <p>{todayNutrition.calories} / {dailyGoals.calories}</p>


  <h3>Macros</h3>
  <p>Protein: {todayNutrition.protein}g</p>
  <p>Carbs: {todayNutrition.carbs}g</p>
  <p>Fat: {todayNutrition.fat}g</p>
</div>


);
}
